def json_dumps(obj: Any) -> bytes:
    return json.dumps(obj, separators=(",", ":"), ensure_ascii=False).encode("utf-8")

def json_loads(b: bytes) -> Any:
    return json.loads(b.decode("utf-8"))

def pack_message(obj: Any, compress: bool = True) -> bytes:
    payload = json_dumps(obj)
    if compress:
        payload = zlib.compress(payload, level=3)
        header = b"Z"
    else:
        header = b"J"
    if len(payload) > MAX_MESSAGE_BYTES:
        raise ValueError("message too large")
    length = len(payload).to_bytes(4, "big")
    return header + length + payload

async def read_exactly(reader: asyncio.StreamReader, n: int) -> bytes:
    data = await reader.readexactly(n)
    return data

async def read_message(reader: asyncio.StreamReader) -> Any:
    header = await read_exactly(reader, 1)
    length = int.from_bytes(await read_exactly(reader, 4), "big")
    if length <= 0 or length > MAX_MESSAGE_BYTES:
        raise ValueError("invalid message size")
    payload = await read_exactly(reader, length)
    if header == b"Z":
        payload = zlib.decompress(payload)
    elif header != b"J":
        raise ValueError("invalid message header")
    return json_loads(payload)

async def write_message(writer: asyncio.StreamWriter, obj: Any, compress: bool = True):
    data = pack_message(obj, compress=compress)
    writer.write(data)
    await writer.drain()

