class GameServer:
    def __init__(self, host: str, port: int):
        self.host = host
        self.port = port
        self.server: Optional[asyncio.AbstractServer] = None

        self.clients: Dict[str, ClientConn] = {}
        self.players: Dict[str, PlayerState] = {}

